import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge cases / simplest ---
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // --- Base premiums for single main items (each base + 5 G fee) ---
  it.todo("single plain sword → premium 105 G (100 base + 5 fee)");
  it.todo("single plain amulet → premium 65 G (60 base + 5 fee)");
  it.todo("single plain staff → premium 85 G (80 base + 5 fee)");
  it.todo("single plain potion → premium 45 G (40 base + 5 fee)");

  // --- Components (runes, moonstones) ---
  it.todo("single rune → premium 30 G (25 base + 5 fee)");
  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
  it.todo("3 runes → premium 65 G (60 base block premium + 5 fee)");
  it.todo("4 runes → premium 105 G (100 base, no block + 5 fee)");
  it.todo("7 runes → premium 180 G (175 base + 5 fee)");

  // --- 'Alike' components clarification ---
  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block: different types + 5 fee)");
  it.todo("3 runes + 3 moonstones → premium 125 G (120 base = two separate blocks + 5 fee)");

  // --- Premium modifiers (item-specific) ---
  it.todo("cursed sword → premium 155 G (100 + 50 curse + 5 fee)");
  it.todo("sword enchantment 5 → premium 135 G (100 + 30 high-ench + 5 fee)");
  it.todo("sword enchantment 4 → premium 105 G (no high-ench surcharge)");
  it.todo("cursed sword enchantment 5 → premium 185 G (100 + 50 + 30 + 5 fee)");

  // --- Loyalty discount (policy-wide) ---
  it.todo("customer 2 years, plain sword → loyalty discount applies → premium 85 G (100 - 20 + 5)");
  it.todo("customer 1 year, plain sword → no loyalty discount → premium 105 G");

  // --- First insurance vs. follow-up contract (policy-wide) ---
  it.todo("first quote, plain sword → +10 G initial assessment → premium 115 G (100 + 10 + 5)");
  it.todo("second quote (follow-up), plain sword → -15 G follow-up discount → premium 90 G (100 + 10 - 15 + 5)");

  // --- Modifier scope on multi-item policy ---
  it.todo("cursed sword + plain amulet → premium 215 G (100 + 60 + 50 curse + 10 first + 5 fee)");

  // --- Rounding (in MHPCO favor) ---
  it.todo("premium calc yielding 197.5 G → final 198 G (round up for premiums)");
  it.todo("payout calc yielding 350.5 G → final 350 G (round down for payouts)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword → premium 165 G (100 + 50 + 10 = 160 + 5)");
  it.todo("long-standing customer's second contract, cursed sword ench 7 → premium 160 G");

  // --- Claim: standard reimbursement (no special clauses) ---
  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 - 100 deductible)");
  it.todo("rune damaged, damage 200 → payout 100 (200 - 100 deductible, no special clause)");

  // --- Claim: special clauses ---
  it.todo("dragon-material sword ench 8, damage 1000 → payout 400 (high-ench 50% then deductible)");
  it.todo("dragon-material sword ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (dragon full, then deductible)");
  it.todo("steel sword ench 9, damage 1000 → payout 400 (high-ench 50%, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon damages sword 500 and amulet 300 → payout 600 (deductible per item)");

  // --- Claim: multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("policy with two swords, damages contains two sword entries → each has its own deductible");
  it.todo("policy with one sword, damages contains two sword entries → CLI exits non-zero (rejected)");

  // --- Claim: cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium 165) → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount doesn't reduce sum)");
  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 cap remaining 600; second payout 600 cap remaining 0");

  // --- Edge cases: errors ---
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
  it.todo("claim references damage entry whose item not in policy → CLI exits non-zero");
  it.todo("claim with damage amount -200 → CLI exits non-zero");
});

