const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;
const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const baseForType = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type)) {
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    return blocks * COMPONENT_BLOCK_BASE + remainder * BASE_PREMIUMS[type];
  }
  return count * BASE_PREMIUMS[type];
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  const countsByType = new Map<string, number>();
  for (const item of items) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let itemsBase = 0;
  for (const [type, count] of countsByType) {
    itemsBase += baseForType(type, count);
  }
  const itemsTotal = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
  return { results: [{ premium }] };
};

