const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const PROCESSING_FEE = 5;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const baseForType = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_BASE;
  }
  return count * BASE_PREMIUMS[type];
};

export const runScenario = (scenario: any): unknown => {
  const results = [];
  let quoteStepsSeen = 0;
  for (const step of scenario.steps) {
    const items = step.items;
    const countsByType = new Map<string, number>();
    for (const item of items) {
      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
    }
    let itemBasesSum = 0;
    for (const [type, count] of countsByType) {
      itemBasesSum += baseForType(type, count);
    }
    let itemSurcharges = 0;
    for (const item of items) {
      const itemBase = BASE_PREMIUMS[item.type];
      if (item.cursed) {
        itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
      }
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
      }
    }
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
      ? itemBasesSum * LOYALTY_DISCOUNT_RATE
      : 0;
    const followUpDiscount = quoteStepsSeen > 0
      ? itemBasesSum * FOLLOW_UP_DISCOUNT_RATE
      : 0;
    const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount + itemSurcharges;
    const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
    results.push({ premium });
    quoteStepsSeen++;
  }
  return { results };
};

