file.content:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const PROCESSING_FEE = 5;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const CAP_MULTIPLIER = 2;
const DEDUCTIBLE = 100;

const baseForType = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_BASE;
  }
  return count * BASE_PREMIUMS[type];
};

export const runScenario = (scenario: any): unknown => {
  const results = [];
  let quoteStepsSeen = 0;
  const policiesByStepIndex = new Map<number, { capRemaining: number; items: any[] }>();
  for (let stepIndex = 0; stepIndex < scenario.steps.length; stepIndex++) {
    const step = scenario.steps[stepIndex];
    if (step.op === "claim") {
      for (const damage of step.incident.damages) {
        if (damage.amount < 0) {
          throw new Error(`damage amount must be non-negative`);
        }
      }
      const policy = policiesByStepIndex.get(step.policy)!;
      const insuredCountsByType = new Map<string, number>();
      for (const item of policy.items) {
        insuredCountsByType.set(item.type, (insuredCountsByType.get(item.type) ?? 0) + 1);
      }
      const damageCountsByType = new Map<string, number>();
      for (const damage of step.incident.damages) {
        damageCountsByType.set(damage.itemType, (damageCountsByType.get(damage.itemType) ?? 0) + 1);
      }
      for (const [type, count] of damageCountsByType) {
        if (count > (insuredCountsByType.get(type) ?? 0)) {
          throw new Error(`damage count for ${type} exceeds insured items`);
        }
      }
      let payout = 0;
      for (const damage of step.incident.damages) {
        const insuredItem = policy.items.find((i: any) => i.type === damage.itemType);
        let base = damage.amount;
        if (insuredItem && insuredItem.enchantment >= 8) {
          base = base * 0.5;
        } else if (insuredItem && insuredItem.material === "dragon") {
          base = base;
        }
        payout += Math.max(0, base - DEDUCTIBLE);
      }
      payout = Math.min(payout, policy.capRemaining);
      policy.capRemaining -= payout;
      results.push({ payout, remainingCap: policy.capRemaining });
      continue;
    }
    const items = step.items;
    for (const item of items) {
      if (!(item.type in BASE_PREMIUMS)) {
        throw new Error(`unknown item type: ${item.type}`);
      }
    }
    const countsByType = new Map<string, number>();
    for (const item of items) {
      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
    }
    let itemBasesSum = 0;
    for (const [type, count] of countsByType) {
      itemBasesSum += baseForType(type, count);
    }
    let itemSurcharges = 0;
    let insuranceSum = 0;
    for (const item of items) {
      const itemBase = BASE_PREMIUMS[item.type];
      if (item.cursed) {
        itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
      }
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
      }
      insuranceSum += INSURANCE_VALUES[item.type];
    }
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
      ? itemBasesSum * LOYALTY_DISCOUNT_RATE
      : 0;
    const followUpDiscount = quoteStepsSeen > 0
      ? itemBasesSum * FOLLOW_UP_DISCOUNT_RATE
      : 0;
    const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount + itemSurcharges;
    const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
    results.push({ premium });
    policiesByStepIndex.set(stepIndex, { capRemaining: insuranceSum * CAP_MULTIPLIER, items });
    quoteStepsSeen++;
  }
  return { results };
};

